public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void BuyHealthPotion()
    {
        int potionCost = 20;
        int healthRestore = 30;

        if (playerStats.currency >= potionCost)
        {
            playerStats.PurchaseItem(potionCost);
            playerStats.health += healthRestore;
            if (playerStats.health > 100) playerStats.health = 100; // cap health
        }
    }

    public void BuyDamageUpgrade()
    {
        int upgradeCost = 50;

        if (playerStats.currency >= upgradeCost)
        {
            playerStats.PurchaseItem(upgradeCost);
            playerStats.damage += 5; // increase damage
        }
    }
}

public class Enemy : MonoBehaviour
{
    public int enemyHealth = 50;
    public int enemyDamage = 5;

    public void Attack(PlayerStats playerStats)
    {
        playerStats.TakeDamage(enemyDamage);
    }

    public void TakeDamage(int damageAmount)
    {
        enemyHealth -= damageAmount;
        if (enemyHealth <= 0) Destroy(gameObject);
